'use strict';

class URLHelper {
    /**
     * Gets url
     */
    static getUrl() {
        return window.location.pathname + window.location.search;
    }
    /**
     * Creates a url object by the fullpath.
     *
     * @param fullpath
     */
    static setUrl(fullpath) {
        if (fullpath) {
            let [pathname, search] = fullpath.split("?");
            if (!search)
                search = "";
            const params = pathname.split("/");
            const querySplit = search.split("&");
            let query = {};
            querySplit.forEach(item => {
                const [key, value] = item.split("=");
                query[key] = value;
            });
            return {
                pathname,
                search,
                fullpath,
                params,
                query
            };
        }
        return null;
    }
    /**
     * Checks the path it if matches in the url
     *
     * @param url
     * @param path
     * @param exact
     */
    static checkPathIfMatches(url, path, exact) {
        if (url) {
            if (path == "/")
                return exact ? url == "/" : true;
            else if (!exact)
                path = path.replace(/(\/)([^\/]+)/g, "($1$2)?");
            return url.match(new RegExp(`^${path}$`)) ? true : false;
        }
        return false;
    }
}

const SET_URL = "SRC_ROUTER_SET_URL";
const SET_NEW_URL = "SRC_ROUTER_SET_NEW_URL";
const SET_CANCEL_CALLBACK = "SRC_ROUTER_SET_CANCEL_CALLBACK";
const SET_PERCENTAGE = "SRC_ROUTER_SET_PERCENTAGE";

const setUrl = (url) => ({
    type: SET_URL,
    payload: URLHelper.setUrl(url)
});
const setNewUrl = (newUrl) => ({
    type: SET_NEW_URL,
    payload: URLHelper.setUrl(newUrl)
});
const setCancelCallback = (callback, key) => ({
    type: SET_CANCEL_CALLBACK,
    payload: callback,
    key
});
const setPercentage = (percentage, key) => ({
    type: SET_PERCENTAGE,
    payload: percentage,
    key
});

exports.SET_CANCEL_CALLBACK = SET_CANCEL_CALLBACK;
exports.SET_NEW_URL = SET_NEW_URL;
exports.SET_PERCENTAGE = SET_PERCENTAGE;
exports.SET_URL = SET_URL;
exports.URLHelper = URLHelper;
exports.setCancelCallback = setCancelCallback;
exports.setNewUrl = setNewUrl;
exports.setPercentage = setPercentage;
exports.setUrl = setUrl;
